class DiskCache:
    """
    Simple disk-based cache with TTL (time-to-live) expiration.
    Values can be any JSON-serializable (or orjson-serializable) object.
    """

    def __init__(self, cache_dir="cache", default_ttl=3600):
        self.cache_dir = os.path.abspath(cache_dir)
        self.default_ttl = default_ttl
        self._lock = RLock()
        os.makedirs(self.cache_dir, exist_ok=True)

    # ---------------- Internal helpers ---------------- #

    def _key_to_filename(self, key: str) -> str:
        """Map a cache key to an absolute filename (SHA256 hashed)."""
        digest = hashlib.sha256(key.encode()).hexdigest()
        return os.path.join(self.cache_dir, digest + ".cache")

    def _is_expired(self, timestamp: float, ttl: int) -> bool:
        """Return True if entry is expired."""
        if ttl < 0:
            return False  # negative TTL -> never expire
        return time.time() > timestamp + ttl

    def _atomic_write(self, path: str, data: bytes):
        """Write bytes to path atomically."""
        tmp_fd, tmp_path = tempfile.mkstemp(dir=self.cache_dir)
        with os.fdopen(tmp_fd, "wb") as tmp_file:
            tmp_file.write(data)
        os.replace(tmp_path, path)

    # ---------------- Public API ---------------- #

    def set(self, key: str, value, ttl: int | None = None):
        """
        Store value under key for ttl seconds.
        ttl=None -> default_ttl
        ttl<0   -> never expire
        """
        if ttl is None:
            ttl = self.default_ttl
        payload = {
            "timestamp": time.time(),
            "ttl": int(ttl),
            "data": value,
        }
        data_bytes = _dumps(payload)
        filename = self._key_to_filename(key)
        with self._lock:
            self._atomic_write(filename, data_bytes)

    def get(self, key: str, default=None):
        """
        Retrieve value for key, or default if missing/expired.
        """
        filename = self._key_to_filename(key)
        try:
            with self._lock:
                with open(filename, "rb") as f:
                    payload = _loads(f.read())
            if self._is_expired(payload["timestamp"], payload["ttl"]):
                # expired: remove file and return default
                self.delete(key)
                return default
            return payload["data"]
        except FileNotFoundError:
            return default
        except Exception:
            # corrupted entry
            self.delete(key)
            return default

    def delete(self, key: str):
        """Delete key from cache, if present."""
        filename = self._key_to_filename(key)
        with self._lock:
            try:
                os.remove(filename)
            except FileNotFoundError:
                pass

    def clear(self):
        """Remove all entries in the cache directory."""
        with self._lock:
            for fname in os.listdir(self.cache_dir):
                path = os.path.join(self.cache_dir, fname)
                try:
                    os.remove(path)
                except FileNotFoundError:
                    continue

    def cleanup(self):
        """Remove expired entries."""
        now = time.time()
        with self._lock:
            for fname in os.listdir(self.cache_dir):
                path = os.path.join(self.cache_dir, fname)
                try:
                    with open(path, "rb") as f:
                        payload = _loads(f.read())
                    if self._is_expired(payload["timestamp"], payload["ttl"]):
                        os.remove(path)
                except Exception:
                    # corrupted file or other error
                    try:
                        os.remove(path)
                    except FileNotFoundError:
                        pass

    # -------------- Dict-like convenience -------------- #

    def __getitem__(self, key):
        value = self.get(key)
        if value is None:
            raise KeyError(key)
        return value

    def __setitem__(self, key, value):
        self.set(key, value)

    def __delitem__(self, key):
        self.delete(key)

    def __contains__(self, key):
        return self.get(key, default=None) is not None


